export const 鎮宅養蠶 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：桿二＋Z折圈鏈＋右圈柱
    桿(0.7, 7.3, 1.0);
    桿(0.7, 7.3, 2.4);
    圈(0.9, 3.9);
    圈(6.0, 3.8);
    圈(1.0, 5.9);
    連([0.9, 3.9], [6.0, 3.8]);
    連([6.0, 3.8], [1.0, 5.9]);
    圈(7.3, 3.7);
    圈(7.4, 5.6);
    圈(6.3, 5.8);
    // 雙目箱層
    線(p => p.M(X(0.8), Z(6.5)).L(X(0.8), Z(9.3)));
    線(p => p.M(X(4.1), Z(6.45)).L(X(4.1), Z(9.25)));
    for (const z of [6.5, 7.9, 9.3])
        線(p => p.M(X(0.8), Z(z)).L(X(4.1), Z(z - 0.05)));
    線(p => p.M(X(4.6), Z(6.6)).L(X(4.6), Z(9.2)));
    線(p => p.M(X(7.2), Z(6.55)).L(X(7.2), Z(9.15)));
    for (const z of [6.6, 7.9, 9.2])
        線(p => p.M(X(4.6), Z(z)).L(X(7.2), Z(z - 0.05)));
    // 密雙目疊（各四箱帶中豎）
    const 疊 = (x0, x1) => {
        線(p => p.M(X(x0), Z(9.8)).L(X(x0), Z(15.8)));
        線(p => p.M(X(x1), Z(9.75)).L(X(x1), Z(15.75)));
        for (let i = 0; i <= 4; i++)
            線(p => p.M(X(x0), Z(9.8 + i * 1.5)).L(X(x1), Z(9.75 + i * 1.5)));
        線(p => p.M(X((x0 + x1) / 2), Z(9.8)).L(X((x0 + x1) / 2 - 0.05), Z(15.8)), 0.34);
    };
    疊(0.8, 3.4);
    疊(4.2, 6.8);
    // 巛螺尾四（S曲收小螺）
    const 蠶 = (x0) => 線(p => p.M(X(x0), Z(16.2))
        .C(X(x0 - 0.4), Z(16.9), X(x0 + 0.4), Z(17.5), X(x0), Z(18.2))
        .C(X(x0 - 0.3), Z(18.7), X(x0 + 0.1), Z(19.1), X(x0 + 0.4), Z(18.9))
        .C(X(x0 + 0.6), Z(18.7), X(x0 + 0.4), Z(18.5), X(x0 + 0.2), Z(18.6)));
    蠶(1.2);
    蠶(2.6);
    蠶(4.4);
    蠶(5.9);
};
